const input = $json.body ?? $json;
const env = $env;

function required(name) {
  const value = env[name];
  if (!value) throw new Error(`${name} is required`);
  return value;
}

function trimSlash(value) {
  return String(value || '').replace(/\/$/, '');
}

function pathEncode(path) {
  return path.split('/').map(encodeURIComponent).join('/');
}

function outputText(response) {
  if (response.output_text) return response.output_text;
  const chunks = [];
  for (const output of response.output || []) {
    for (const content of output.content || []) {
      if (content.text) chunks.push(content.text);
    }
  }
  return chunks.join('\n').trim();
}

async function requestJson(url, init) {
  const response = await fetch(url, init);
  const raw = await response.text();
  const data = raw ? JSON.parse(raw) : {};
  if (!response.ok) {
    throw new Error(`${init.method || 'GET'} ${url} returned ${response.status}: ${raw.slice(0, 700)}`);
  }
  return data;
}

async function postHub(path, body) {
  const hubBase = trimSlash(required('ORCHESTRATOR_HUB_API_BASE_URL'));
  return requestJson(`${hubBase}${path}`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${required('ORCHESTRATOR_N8N_CALLBACK_TOKEN')}`
    },
    body: JSON.stringify(body)
  });
}

async function putGitHubFile(project, path, markdown, message) {
  const token = required('GITHUB_TOKEN');
  const url = `https://api.github.com/repos/${project.github_owner}/${project.github_repo}/contents/${pathEncode(path)}`;
  const body = {
    message,
    branch: project.default_branch || 'main',
    content: Buffer.from(markdown, 'utf8').toString('base64'),
    committer: {
      name: env.ORCHESTRATOR_GIT_AUTHOR_NAME || 'anton415-orchestrator',
      email: env.ORCHESTRATOR_GIT_AUTHOR_EMAIL || 'orchestrator@anton415.local'
    }
  };
  return requestJson(url, {
    method: 'PUT',
    headers: {
      'Accept': 'application/vnd.github+json',
      'Authorization': `Bearer ${token}`,
      'X-GitHub-Api-Version': env.GITHUB_API_VERSION || '2026-03-10',
      'Content-Type': 'application/json'
    },
    body: JSON.stringify(body)
  });
}

const workflowId = input.workflow_id;
const project = input.project;
const feature = input.feature;
if (!workflowId || !project || !feature) {
  throw new Error('workflow_id, project, and feature are required');
}

const prompt = `You are a senior systems analyst.
Goal:
Convert the feature idea into a clear specification.
Rules:
- Do not design architecture.
- Do not write implementation details.
- Separate facts, assumptions, and open questions.
- Keep the scope small.
- Produce testable acceptance criteria.
- Output Markdown only.
Feature:
Title: ${feature.title}
Module: ${feature.module || 'unknown'}
Problem: ${feature.problem}
Required sections:
# Problem
# Context
# User Story
# Scope
## In Scope
## Out of Scope
# Acceptance Criteria
# Edge Cases
# Risks
# Open Questions
# Definition of Done`;

const openaiResponse = await requestJson('https://api.openai.com/v1/responses', {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'Authorization': `Bearer ${required('OPENAI_API_KEY')}`
  },
  body: JSON.stringify({
    model: env.OPENAI_MODEL || 'gpt-5.2',
    input: prompt,
    max_output_tokens: 5000
  })
});

const specBody = outputText(openaiResponse);
if (!specBody) throw new Error('OpenAI returned an empty spec');

const specMarkdown = `---
feature_id: "${feature.id}"
title: "${feature.title}"
module: "${feature.module || ''}"
status: "spec_review"
created_by: "chatgpt"
---

${specBody}\n`;
const specPath = `docs/specs/${feature.id}.md`;
const githubResult = await putGitHubFile(project, specPath, specMarkdown, `docs(orchestrator): add spec for ${feature.id}`);
const githubUrl = githubResult.content?.html_url || null;

await postHub('/api/v1/orchestrator/n8n/artifacts', {
  workflow_id: workflowId,
  artifact_type: 'spec',
  title: 'System specification',
  github_url: githubUrl,
  local_preview: specMarkdown,
  created_by_agent: 'chatgpt'
});
await postHub('/api/v1/orchestrator/n8n/events', {
  workflow_id: workflowId,
  source: 'n8n',
  event_type: 'spec_generated',
  message: 'ChatGPT generated system specification',
  payload: {
    artifact_type: 'spec',
    github_url: githubUrl,
    path: specPath
  }
});

return [{ json: { workflow_id: workflowId, status: 'spec_review', spec_path: specPath, github_url: githubUrl } }];

const input = $json.body ?? $json;
const env = $env;

function required(name) {
  const value = env[name];
  if (!value) throw new Error(`${name} is required`);
  return value;
}

function trimSlash(value) {
  return String(value || '').replace(/\/$/, '');
}

function pathEncode(path) {
  return path.split('/').map(encodeURIComponent).join('/');
}

function artifact(type) {
  return (input.artifacts || []).find((item) => item.type === type || item.artifact_type === type);
}

function artifactPreview(type) {
  const found = artifact(type);
  return found?.local_preview || found?.github_url || '';
}

function claudeText(response) {
  return (response.content || []).filter((part) => part.type === 'text').map((part) => part.text).join('\n').trim();
}

