async function createGitHubIssue(project, title, body) {
  return requestJson(`https://api.github.com/repos/${project.github_owner}/${project.github_repo}/issues`, {
    method: 'POST',
    headers: {
      'Accept': 'application/vnd.github+json',
      'Authorization': `Bearer ${required('GITHUB_TOKEN')}`,
      'X-GitHub-Api-Version': env.GITHUB_API_VERSION || '2026-03-10',
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({ title, body })
  });
}

const workflowId = input.workflow_id;
const project = input.project;
const feature = input.feature;
if (!workflowId || !project || !feature) {
  throw new Error('workflow_id, project, and feature are required in approval payload');
}

const approved = input.decision === 'approved' || input.decision === 'approved_anyway';
if (!approved) {
  await postHub('/api/v1/orchestrator/n8n/events', {
    workflow_id: workflowId,
    source: 'n8n',
    event_type: 'approval_stopped',
    message: `Approval webhook received ${input.decision} for ${input.step_key}; automation stopped`,
    payload: { step_key: input.step_key, decision: input.decision, comment: input.comment || null }
  });
  return [{ json: { workflow_id: workflowId, status: 'stopped', decision: input.decision } }];
}

if (input.step_key === 'spec_approval') {
  const specMarkdown = artifactPreview('spec');
  if (!specMarkdown) throw new Error('spec artifact preview is required for architecture generation');

  const architecturePrompt = `You are a senior software architect.
Goal:
Convert the approved specification into a practical architecture plan.
Rules:
- Do not rewrite product requirements.
- If the spec has problems, add Architecture Concerns.
- Prefer small reversible changes.
- Respect the project stack.
- Avoid overengineering.
- Include test plan and rollback plan.
- Output Markdown only.
Approved specification:
${specMarkdown}
Project stack:
backend: go
frontend: react
runtime: docker
repo: ${project.github_owner}/${project.github_repo}
Required sections:
# Architecture Summary
# Affected Modules
# Backend Changes
# Frontend Changes
# Database Changes
# API Changes
# Security / Privacy Considerations
# Test Plan
# Implementation Steps
# Rollback Plan
# Architecture Concerns
# Open Questions`;

  const claudeResponse = await requestJson('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': required('ANTHROPIC_API_KEY'),
      'anthropic-version': '2023-06-01'
    },
    body: JSON.stringify({
      model: env.ANTHROPIC_MODEL || 'claude-sonnet-4-5',
      max_tokens: 5000,
      messages: [{ role: 'user', content: architecturePrompt }]
    })
  });

  const architectureBody = claudeText(claudeResponse);
  if (!architectureBody) throw new Error('Anthropic returned an empty architecture plan');
  const architectureMarkdown = `---
feature_id: "${feature.id}"
title: "${feature.title}"
module: "${feature.module || ''}"
status: "architecture_review"
created_by: "claude"
---

${architectureBody}\n`;
  const architecturePath = `docs/architecture/${feature.id}.md`;
  const githubResult = await putGitHubFile(project, architecturePath, architectureMarkdown, `docs(orchestrator): add architecture for ${feature.id}`);
  const githubUrl = githubResult.content?.html_url || null;

  await postHub('/api/v1/orchestrator/n8n/artifacts', {
    workflow_id: workflowId,
    artifact_type: 'architecture',
    title: 'Architecture plan',
    github_url: githubUrl,
    local_preview: architectureMarkdown,
    created_by_agent: 'claude'
  });
  await postHub('/api/v1/orchestrator/n8n/events', {
    workflow_id: workflowId,
    source: 'n8n',
    event_type: 'architecture_generated',
    message: 'Claude generated architecture plan',
    payload: {
      artifact_type: 'architecture',
      github_url: githubUrl,
      path: architecturePath
    }
  });
  return [{ json: { workflow_id: workflowId, status: 'architecture_review', architecture_path: architecturePath, github_url: githubUrl } }];
}

if (input.step_key === 'architecture_approval') {
  const specMarkdown = artifactPreview('spec');
  const architectureMarkdown = artifactPreview('architecture');
  if (!architectureMarkdown) throw new Error('architecture artifact preview is required for Codex prompt generation');

  const codexPrompt = `# Codex Implementation Task

You are implementing an approved feature.

Repository:
${project.github_owner}/${project.github_repo}

Feature:
${feature.title}

Inputs:
- Spec artifact: ${artifact('spec')?.github_url || 'stored in Hub artifact preview'}
- Architecture artifact: ${artifact('architecture')?.github_url || 'stored in Hub artifact preview'}

Rules:
- Follow the approved architecture plan.
- Make the smallest correct change.
- Do not rewrite unrelated code.
- Add or update tests.
- Update docs if behavior changes.
- Do not merge.
- Open a PR.

Approved specification:
${specMarkdown || '(spec preview unavailable)'}

Approved architecture:
${architectureMarkdown}

Deliverables:
- implementation commits;
- tests;
- PR description;
- notes about risks or blockers.
`;

  const issueBody = `## Status
ready_for_implementation

## Project
${project.github_owner}/${project.github_repo}

## Artifacts
- Spec: ${artifact('spec')?.github_url || 'stored in Hub'}
- Architecture: ${artifact('architecture')?.github_url || 'stored in Hub'}

## Approvals
- Spec: approved via Hub
- Architecture: approved via Hub

## AI Roles
- ChatGPT: system analysis
- Claude: architecture
- Codex: implementation

## Workflow
Hub workflow id: ${workflowId}

## Codex Prompt

${codexPrompt}`;

  const issue = await createGitHubIssue(project, `Feature: ${feature.title}`, issueBody);

  await postHub('/api/v1/orchestrator/n8n/artifacts', {
    workflow_id: workflowId,
    artifact_type: 'codex_prompt',
    title: 'Codex implementation prompt',
    github_url: issue.html_url || null,
    local_preview: codexPrompt,
    created_by_agent: 'codex'
  });
  await postHub('/api/v1/orchestrator/n8n/status', {
    workflow_id: workflowId,
    status: 'ready_for_implementation',
    github_issue_url: issue.html_url || null,
    step_key: 'ready_for_implementation',
    step_status: 'done'
  });
  await postHub('/api/v1/orchestrator/n8n/events', {
    workflow_id: workflowId,
    source: 'n8n',
    event_type: 'ready_for_implementation',
    message: 'Codex prompt generated and GitHub issue created',
    payload: {
      artifact_type: 'codex_prompt',
      github_issue_url: issue.html_url || null,
      issue_number: issue.number || null
    }
  });
  return [{ json: { workflow_id: workflowId, status: 'ready_for_implementation', github_issue_url: issue.html_url || null } }];
}

await postHub('/api/v1/orchestrator/n8n/events', {
  workflow_id: workflowId,
  source: 'n8n',
  event_type: 'approval_ignored',
  message: `Approval webhook ignored unsupported step ${input.step_key}`,
  payload: { step_key: input.step_key, decision: input.decision }
});
return [{ json: { workflow_id: workflowId, status: 'ignored', step_key: input.step_key } }];
